    public static IReadOnlyList<InstructionArticle> All { get; } =
    [
        Article("disp.intro", "Диспетчерская — обзор", 51,
        [
            P("Модуль «Диспетчерская» в меню слева — это ваш рабочий стол на каждый учебный день. Здесь вы смотрите, какие уроки идут в выбранную дату, оформляете замены, когда учитель не выйдет, и вносите разовые правки только на один день — смена кабинета, сокращённый день, перестановка двух уроков. Всё это не трогает недельное расписание в конструкторе: завтра снова подтянется обычная сетка."),
            P("Перед работой в диспетчерской должны быть заполнены справочники, сетка в конструкторе, период на учебный год и календарь. Иначе на дату просто не из чего показать уроки — даже если вы вчера всё расставили в сетке."),
            H("С чего начать каждый день"),
            P("Откройте «Диспетчерская». В шапке страницы первым делом укажите «Дата:» — календарь с выбором дня. Без даты вкладки внизу не покажут расписание. Выберите сегодня или любой другой учебный день, с которым работаете."),
            P("Посмотрите на счётчик «Без замены: N» рядом с заголовком. Это число уроков, на которые ещё не назначен заменяющий педагог. Утром цель простая: довести до «Без замены: 0», если кто-то отсутствует."),
            H("Три вкладки внизу"),
            P("«Монитор» — вся школа на выбранную дату одним экраном. Удобно повесить на второй монитор: видно, кто где, какие замены ещё нужны, какой урок идёт сейчас. Переключатель «Строки:» меняет, что в строках таблицы: педагоги, классы или кабинеты."),
            P("«Замены» — основная работа с отсутствиями. Внутри две подвкладки: «Замены на день» (отметить больничный, подобрать и назначить замену на каждый урок) и «Журнал и отчёт» (посмотреть замены и отсутствия за месяц или четверть, выгрузить в Excel)."),
            P("«Конструктор дня» — правки только на выбранную дату: другой кабинет из-за ремонта, сокращённый день по приказу, поменять два урока местами, отменить последние уроки класса. Подробнее — в статьях раздела «Конструктор дня»."),
            H("Кнопки в шапке"),
            P("«Обновить» (F5) — перечитать данные с диска. Нажимайте после того, как правили сетку в конструкторе или справочники — иначе на экране может остаться старая картина."),
            P("«Excel» — выгрузить список замен на выбранную дату в таблицу. «В буфер» и «PNG» — картинка расписания дня: можно вставить в чат коллегам или повесить на стенд в диспетчерской."),
            P("Рядом с датой могут быть карточки-подсказки: ближайшее событие из календаря (каникулы, праздник) и напоминание о текущем учебном периоде. Это помогает не забыть, что скоро меняется режим."),
            H("Если на дату «уроков нет»"),
            P("Не спешите править сетку — сначала проверьте три вещи в конструкторе."),
            P("«Конструктор» → «Календарь». Не попадает ли выбранная дата на каникулы или «Праздник / выходной»? В эти дни уроков не будет, даже если сетка заполнена."),
            P("«Конструктор» → «Период». Есть ли запись, у которой дата попадает между полями «С» и «По»? Период начинает действовать сам по датам — отдельной галочки «включить» нет. Если периода на эту дату нет, программа не знает, какую неделю показывать."),
            P("Суббота. Обычная суббота без уроков. Уроки в субботу бывают только если в календаре добавлена «Компенсационная суббота» на эту дату."),
            P("После проверки нажмите «Обновить» (F5) в диспетчерской."),
